sql:
SELECT title 
FROM media_titles 
WHERE rating > (SELECT AVG(rating) FROM media_titles);

SELECT title 
FROM media_titles 
WHERE type = 'Movie' AND duration > (SELECT AVG(duration) FROM media_titles WHERE type = 'Movie');

SELECT title, year
FROM media_titles
WHERE rating > 9.0;

SELECT AVG(duration) AS average_duration
FROM media_titles
WHERE type = 'Movie' AND year > 2000;

SELECT ltable_title
FROM media_relationships
WHERE relation_type = 'Sequel';

SELECT media_titles.title, production_houses.house_name
FROM media_titles
JOIN production_houses ON media_titles.production_house_id = production_houses.house_id;

SELECT title, genres 
FROM media_titles
ORDER BY rating DESC;

SELECT title, year, rating 
FROM media_titles 
WHERE type = 'Movie' AND rating > 8.0 AND year = '2010';

external_knowledge:
- "short film gems" refers to movies with a duration of less than 90 minutes;
- "audience footprint" metaphorically represents the number of views a media title has;
- "critical acclaim" is synonymous with the rating given to a film;
- "visionary masters" here refer to directors;
- "have resonated with more than a million hearts" means that these media titles have been viewed more than 1,000,000 times;
- "cinematic pearls" signifies movies of high quality;
- "luster" and "popularity" correspond to rating and views, respectively, in the metaphorical sense.

